// ---------------------------------------------------------------------------
// Web search tool implementation using DuckDuckGo Instant Answer API
// ---------------------------------------------------------------------------
static async Task<string> WebSearchAsync(string query, IHttpClientFactory httpFactory)
{
    using var client = httpFactory.CreateClient("WebSearch");

    var encoded = Uri.EscapeDataString(query);
    var url = $"https://duckduckgo.com/html/?q={encoded}";

    try
    {
        var html = await client.GetStringAsync(url);
        var results = ParseDuckDuckGoResults(html);

        if (results.Count == 0)
            return $"No results found for '{query}'.";

        return string.Join("\n\n", results.Take(5).Select((r, i) =>
            $"[{i + 1}] {r.Title}\n    {r.Snippet}\n    URL: {r.Url}"));
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static List<SearchResult> ParseDuckDuckGoResults(string html)
{
    var results = new List<SearchResult>();

    // Parse result blocks from DuckDuckGo HTML search results
    var resultSpan = html.AsSpan();
    const string resultMarker = "class=\"result__body";

    int pos = 0;
    while (pos < html.Length && results.Count < 8)
    {
        var idx = html.IndexOf(resultMarker, pos, StringComparison.Ordinal);
        if (idx < 0) break;

        // Extract title
        var titleStart = html.IndexOf("class=\"result__a\"", idx, StringComparison.Ordinal);
        string title = "", url = "", snippet = "";

        if (titleStart >= 0)
        {
            // Get href
            var hrefStart = html.LastIndexOf("href=\"", titleStart, titleStart - idx, StringComparison.Ordinal);
            if (hrefStart >= 0)
            {
                hrefStart += 6;
                var hrefEnd = html.IndexOf('"', hrefStart);
                if (hrefEnd > hrefStart)
                    url = System.Net.WebUtility.HtmlDecode(html[hrefStart..hrefEnd]);
            }

            // Get title text
            var tagEnd = html.IndexOf('>', titleStart);
            if (tagEnd >= 0)
            {
                var closeTag = html.IndexOf("</a>", tagEnd, StringComparison.Ordinal);
                if (closeTag > tagEnd)
                    title = StripHtml(html[(tagEnd + 1)..closeTag]);
            }
        }

        // Extract snippet
        var snippetStart = html.IndexOf("class=\"result__snippet", idx, StringComparison.Ordinal);
        if (snippetStart >= 0)
        {
            var tagEnd = html.IndexOf('>', snippetStart);
            if (tagEnd >= 0)
            {
                var closeTag = html.IndexOf("</a>", tagEnd, StringComparison.Ordinal);
                if (closeTag < 0)
                    closeTag = html.IndexOf("</span>", tagEnd, StringComparison.Ordinal);
                if (closeTag > tagEnd)
                    snippet = StripHtml(html[(tagEnd + 1)..closeTag]);
            }
        }

        if (!string.IsNullOrWhiteSpace(title))
            results.Add(new SearchResult(title.Trim(), snippet.Trim(), url.Trim()));

        pos = idx + resultMarker.Length;
    }

    return results;
}

static string StripHtml(string html)
{
    var result = new System.Text.StringBuilder(html.Length);
    bool inTag = false;
    foreach (var c in html)
    {
        if (c == '<') { inTag = true; continue; }
        if (c == '>') { inTag = false; continue; }
        if (!inTag) result.Append(c);
    }
    return System.Net.WebUtility.HtmlDecode(result.ToString());
}

// ---------------------------------------------------------------------------
// Supporting types
// ---------------------------------------------------------------------------

record SearchResult(string Title, string Snippet, string Url);

/// <summary>Simple in-memory notepad for the agent to collect research findings.</summary>
class Notepad
{
    private readonly List<string> _notes = [];

    public string Add(string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }

    public void Clear() => _notes.Clear();
}

